@Override
	public List<T> findAllById(Iterable<ID> ids) {

		Assert.notNull(ids, IDS_MUST_NOT_BE_NULL);

		if (!ids.iterator().hasNext()) {
			return Collections.emptyList();
		}

		if (entityInformation.hasCompositeId()) {

			List<T> results = new ArrayList<>();

			for (ID id : ids) {
				findById(id).ifPresent(results::add);
			}

			return results;
		}

		Collection<ID> idCollection = toCollection(ids);

		TypedQuery<T> query = getQuery((root, q, criteriaBuilder) -> {

			Path<?> path = root.get(entityInformation.getIdAttribute());
			return path.in(idCollection);

		}, Sort.unsorted());

		return query.getResultList();
	}

@Override
		public Iterable<Entry> selectImports() {
			if (this.autoConfigurationEntries.isEmpty()) {
				return Collections.emptyList();
			}
			Set<String> allExclusions = this.autoConfigurationEntries.stream()
				.map(AutoConfigurationEntry::getExclusions)
				.flatMap(Collection::stream)
				.collect(Collectors.toSet());
			Set<String> processedConfigurations = this.autoConfigurationEntries.stream()
				.map(AutoConfigurationEntry::getConfigurations)
				.flatMap(Collection::stream)
				.collect(Collectors.toCollection(LinkedHashSet::new));
			processedConfigurations.removeAll(allExclusions);
			return sortAutoConfigurations(processedConfigurations, getAutoConfigurationMetadata()).stream()
				.map(this::getEntry)
				.toList();
		}

@Override
	public ConditionOutcome getMatchOutcome(ConditionContext context, AnnotatedTypeMetadata metadata) {
		MergedAnnotations mergedAnnotations = metadata.getAnnotations();
		List<MergedAnnotation<Annotation>> annotations = stream(mergedAnnotations).toList();
		List<ConditionMessage> noMatch = new ArrayList<>();
		List<ConditionMessage> match = new ArrayList<>();
		for (MergedAnnotation<Annotation> annotation : annotations) {
			ConditionOutcome outcome = determineOutcome(annotation, context.getEnvironment());
			(outcome.isMatch() ? match : noMatch).add(outcome.getConditionMessage());
		}
		if (!noMatch.isEmpty()) {
			return ConditionOutcome.noMatch(ConditionMessage.of(noMatch));
		}
		return ConditionOutcome.match(ConditionMessage.of(match));
	}

private <P extends SslBundleProperties> void registerBundles(SslBundleRegistry registry, Map<String, P> properties,
			BiFunction<P, ResourceLoader, SslBundle> bundleFactory, Function<Bundle<P>, Set<Path>> watchedPaths) {
		properties.forEach((bundleName, bundleProperties) -> {
			Supplier<SslBundle> bundleSupplier = () -> bundleFactory.apply(bundleProperties, this.resourceLoader);
			try {
				registry.registerBundle(bundleName, bundleSupplier.get());
				if (bundleProperties.isReloadOnUpdate()) {
					Supplier<Set<Path>> pathsSupplier = () -> watchedPaths
						.apply(new Bundle<>(bundleName, bundleProperties));
					watchForUpdates(registry, bundleName, pathsSupplier, bundleSupplier);
				}
			}
			catch (IllegalStateException ex) {
				throw new IllegalStateException("Unable to register SSL bundle '%s'".formatted(bundleName), ex);
			}
		});
	}

private boolean hasScheduledTask(Class<?> type) {
	Class<?> targetType = ClassUtils.getUserClass(type);
	if (!this.nonAnnotatedClasses.contains(targetType)
			&& AnnotationUtils.isCandidateClass(targetType, Arrays.asList(Scheduled.class, Schedules.class))) {
		Map<Method, Set<Scheduled>> annotatedMethods = MethodIntrospector.selectMethods(targetType,
				(MethodIntrospector.MetadataLookup<Set<Scheduled>>) (method) -> {
					Set<Scheduled> scheduledAnnotations = AnnotatedElementUtils
						.getMergedRepeatableAnnotations(method, Scheduled.class, Schedules.class);
					return (!scheduledAnnotations.isEmpty() ? scheduledAnnotations : null);
				});
		if (annotatedMethods.isEmpty()) {
			this.nonAnnotatedClasses.add(targetType);
		}
		return !annotatedMethods.isEmpty();
	}
	return false;
}

protected @Nullable SslBundle getSslBundle(RunningService service) {
	if (this.sslBundle != null) {
		return this.sslBundle;
	}
	SslBundle jksSslBundle = getJksSslBundle(service);
	SslBundle pemSslBundle = getPemSslBundle(service);
	if (jksSslBundle == null && pemSslBundle == null) {
		return null;
	}
	if (jksSslBundle != null && pemSslBundle != null) {
		throw new IllegalStateException("Mutually exclusive JKS and PEM ssl bundles have been configured");
	}
	SslBundle sslBundle = (jksSslBundle != null) ? jksSslBundle : pemSslBundle;
	this.sslBundle = sslBundle;
	return sslBundle;
}

private void append(StringBuilder report, Map<String, List<PropertyMigration>> content) {
	content.forEach((name, properties) -> {
		report.append(String.format("Property source '%s':%n", name));
		properties.sort(PropertyMigration.COMPARATOR);
		properties.forEach((property) -> {
			report.append(String.format("\tKey: %s%n", property.getProperty().getName()));
			if (property.getLineNumber() != null) {
				report.append(String.format("\t\tLine: %d%n", property.getLineNumber()));
			}
			report.append(String.format("\t\t%s%n", property.determineReason()));
		});
		report.append(String.format("%n"));
	});
}

@SuppressWarnings("unchecked")
	private <R extends ConfigDataResource> ConfigDataLoader<R> getLoader(ConfigDataLoaderContext context, R resource) {
		ConfigDataLoader<R> result = null;
		for (int i = 0; i < this.loaders.size(); i++) {
			ConfigDataLoader<R> candidate = this.loaders.get(i);
			if (this.resourceTypes.get(i).isInstance(resource)) {
				if (candidate.isLoadable(context, resource)) {
					if (result != null) {
						throw new IllegalStateException("Multiple loaders found for resource '" + resource + "' ["
								+ candidate.getClass().getName() + "," + result.getClass().getName() + "]");
					}
					result = candidate;
				}
			}
		}
		Assert.state(result != null, () -> "No loader found for resource '" + resource + "'");
		return result;
	}

@SuppressWarnings("unchecked")
		static <T> @Nullable Bean<T> get(Bindable<T> bindable, Context context, boolean canCallGetValue) {
			ResolvableType type = bindable.getType();
			Class<?> resolvedType = type.resolve(Object.class);
			Supplier<T> value = bindable.getValue();
			T instance = null;
			if (canCallGetValue && value != null) {
				instance = value.get();
				resolvedType = (instance != null) ? instance.getClass() : resolvedType;
			}
			if (instance == null && !isInstantiable(resolvedType)) {
				return null;
			}
			Map<CacheKey, Bean<?>> cache = getCache(context);
			CacheKey cacheKey = new CacheKey(type, resolvedType);
			Bean<?> bean = cache.get(cacheKey);
			if (bean == null) {
				bean = new Bean<>(type, resolvedType);
				cache.put(cacheKey, bean);
			}
			return (Bean<T>) bean;
		}

private <T> @Nullable T getBoundField(Map<ConfigurationPropertyName, T> boundFields, @Nullable String field) {
	if (field == null) {
		return null;
	}
	try {
		ConfigurationPropertyName name = getName(field);
		T bound = boundFields.get(name);
		if (bound != null) {
			return bound;
		}
		if (name.hasIndexedElement()) {
			for (Map.Entry<ConfigurationPropertyName, T> entry : boundFields.entrySet()) {
				if (isFieldNameMatch(entry.getKey(), name)) {
					return entry.getValue();
				}
			}
		}
	}
	catch (Exception ex) {
		// Ignore
	}
	return null;
}

public static @Nullable ConfigurationPropertiesBean get(ApplicationContext applicationContext, Object bean,
			String beanName) {
		Method factoryMethod = findFactoryMethod(applicationContext, beanName);
		Bindable<Object> bindTarget = createBindTarget(bean, bean.getClass(), factoryMethod);
		if (bindTarget == null) {
			return null;
		}
		bindTarget = bindTarget.withBindMethod(BindMethodAttribute.get(applicationContext, beanName));
		if (bindTarget.getBindMethod() == null && factoryMethod != null) {
			bindTarget = bindTarget.withBindMethod(BindMethod.JAVA_BEAN);
		}
		if (bindTarget.getBindMethod() != BindMethod.VALUE_OBJECT) {
			bindTarget = bindTarget.withExistingValue(bean);
		}
		return create(beanName, bean, bindTarget);
	}

@Override
	public @Nullable ConfigurationPropertiesReflectionHintsContribution processAheadOfTime(
			ConfigurableListableBeanFactory beanFactory) {
		String[] beanNames = beanFactory.getBeanNamesForAnnotation(ConfigurationProperties.class);
		List<Bindable<?>> bindables = new ArrayList<>();
		for (String beanName : beanNames) {
			Class<?> beanType = beanFactory.getType(beanName, false);
			if (beanType != null) {
				BindMethod bindMethod = beanFactory.containsBeanDefinition(beanName)
						? (BindMethod) beanFactory.getBeanDefinition(beanName).getAttribute(BindMethod.class.getName())
						: null;
				bindables.add(Bindable.of(ClassUtils.getUserClass(beanType))
					.withBindMethod((bindMethod != null) ? bindMethod : BindMethod.JAVA_BEAN));
			}
		}
		return (!bindables.isEmpty()) ? new ConfigurationPropertiesReflectionHintsContribution(bindables) : null;
	}

private Set<String> getPackagesToScan(AnnotationMetadata metadata) {
	AnnotationAttributes attributes = AnnotationAttributes
		.fromMap(metadata.getAnnotationAttributes(ConfigurationPropertiesScan.class.getName()));
	Assert.state(attributes != null, "'attributes' must not be null");
	String[] basePackages = attributes.getStringArray("basePackages");
	Class<?>[] basePackageClasses = attributes.getClassArray("basePackageClasses");
	Set<String> packagesToScan = new LinkedHashSet<>(Arrays.asList(basePackages));
	for (Class<?> basePackageClass : basePackageClasses) {
		packagesToScan.add(ClassUtils.getPackageName(basePackageClass));
	}
	if (packagesToScan.isEmpty()) {
		packagesToScan.add(ClassUtils.getPackageName(metadata.getClassName()));
	}
	packagesToScan.removeIf((candidate) -> !StringUtils.hasText(candidate));
	return packagesToScan;
}

private @Nullable DependencyCycle findCycle(Throwable rootFailure) {
	List<BeanInCycle> beansInCycle = new ArrayList<>();
	Throwable candidate = rootFailure;
	int cycleStart = -1;
	while (candidate != null) {
		BeanInCycle beanInCycle = BeanInCycle.get(candidate);
		if (beanInCycle != null) {
			int index = beansInCycle.indexOf(beanInCycle);
			if (index == -1) {
				beansInCycle.add(beanInCycle);
			}
			cycleStart = (cycleStart != -1) ? cycleStart : index;
		}
		candidate = candidate.getCause();
	}
	if (cycleStart == -1) {
		return null;
	}
	return new DependencyCycle(beansInCycle, cycleStart);
}

static Map<String, PropertyFile> findAll(Path sourceDirectory, Set<Option> options) {
	try {
		Map<String, PropertyFile> propertyFiles = new TreeMap<>();
		try (Stream<Path> pathStream = Files.find(sourceDirectory, MAX_DEPTH, PropertyFile::isPropertyFile,
				FileVisitOption.FOLLOW_LINKS)) {
			pathStream.forEach((path) -> {
				String name = getName(sourceDirectory.relativize(path));
				if (StringUtils.hasText(name)) {
					if (options.contains(Option.USE_LOWERCASE_NAMES)) {
						name = name.toLowerCase(Locale.getDefault());
					}
					propertyFiles.put(name, new PropertyFile(path, options));
				}
			});
		}
		return Collections.unmodifiableMap(propertyFiles);
	}
	catch (IOException ex) {
		throw new IllegalStateException("Unable to find files in '" + sourceDirectory + "'", ex);
	}
}

private <T> List<Entry<String, T>> getOrderedBeansOfType(ListableBeanFactory beanFactory, Class<T> type,
			Seen seen) {
		String[] names = beanFactory.getBeanNamesForType(type, true, false);
		Map<String, T> map = new LinkedHashMap<>();
		for (String name : names) {
			if (!seen.contains(type, name) && !ScopedProxyUtils.isScopedTarget(name)) {
				T bean = beanFactory.getBean(name, type);
				if (!seen.contains(type, bean)) {
					map.put(name, bean);
				}
			}
		}
		List<Entry<String, T>> beans = new ArrayList<>(map.entrySet());
		beans.sort((o1, o2) -> AnnotationAwareOrderComparator.INSTANCE.compare(o1.getValue(), o2.getValue()));
		return beans;
	}

